<?php
if (!defined('SDS_PERPUSTAKAAN_APP')) { http_response_code(403); exit('Akses langsung tidak diizinkan.'); }
$page='reservasi'; require __DIR__.'/../partials/bootstrap.php'; if(empty($perpusAccess['allowed'])) return;
$message='';$error='';$adminId=(int)($_SESSION['admin_id']??0);
try{sds_perpus_expire_reservations($conn,300);}catch(Throwable $e){error_log('[Reservasi expire] '.$e->getMessage());}
if(($_SERVER['REQUEST_METHOD']??'')==='POST'){
 try{
  perpus_check_csrf();$action=(string)($_POST['action']??'');$id=(int)($_POST['id']??0);
  if(!$perpusCanManage)throw new RuntimeException('Hanya admin Perpustakaan yang dapat memproses reservasi.');
  if($action==='process_queue'){
   $processed=0;$r=$conn->query("SELECT DISTINCT buku_id FROM perpus_reservasi WHERE status='menunggu' ORDER BY tanggal_reservasi LIMIT 300");while($r&&($x=$r->fetch_assoc()))if(sds_perpus_promote_next_reservation($conn,(int)$x['buku_id'],$adminId))$processed++;
   sds_perpus_audit_log($conn,'sync','reservasi','','Sinkronisasi antrean reservasi',null,['siap'=>$processed],$adminId);$message='Sinkronisasi antrian selesai. '.$processed.' reservasi dinyatakan siap.';
  }elseif(in_array($action,['ready','cancel','taken','expire'],true)){
   if($id<=0)throw new RuntimeException('Reservasi tidak valid.');$conn->begin_transaction();
   $stmt=$conn->prepare('SELECT r.*,b.judul FROM perpus_reservasi r JOIN perpus_buku b ON b.id=r.buku_id WHERE r.id=? LIMIT 1 FOR UPDATE');$stmt->bind_param('i',$id);$stmt->execute();$row=$stmt->get_result()->fetch_assoc();$stmt->close();if(!$row)throw new RuntimeException('Reservasi tidak ditemukan.');
   $memberId=(int)$row['anggota_id'];$bookId=(int)$row['buku_id'];$title=(string)$row['judul'];
   if($action==='ready'){
    if(!in_array($row['status'],['menunggu','siap'],true))throw new RuntimeException('Reservasi ini tidak dapat dinyatakan siap.');
    $available=sds_perpus_reservation_available_count($conn,$bookId);if($available<=0)throw new RuntimeException('Belum ada eksemplar tersedia untuk koleksi ini.');$stmt=$conn->prepare("SELECT COUNT(*) total FROM perpus_reservasi WHERE buku_id=? AND status='siap' AND id<>? AND (batas_ambil IS NULL OR batas_ambil>=NOW())");$stmt->bind_param('ii',$bookId,$id);$stmt->execute();$readyCount=(int)($stmt->get_result()->fetch_assoc()['total']??0);$stmt->close();if($readyCount>=$available)throw new RuntimeException('Seluruh eksemplar tersedia sudah dialokasikan untuk reservasi lain.');
    $days=max(1,(int)sds_perpus_setting_value($conn,'reservasi_hari_ambil','2'));$deadline=(new DateTimeImmutable())->modify('+'.$days.' days')->format('Y-m-d H:i:s');
    $stmt=$conn->prepare("UPDATE perpus_reservasi SET status='siap',tanggal_siap=NOW(),batas_ambil=?,admin_id=? WHERE id=?");$stmt->bind_param('sii',$deadline,$adminId,$id);$stmt->execute();$stmt->close();
    sds_perpus_notify_member($conn,$memberId,'reservasi_siap','Reservasi siap diambil','Koleksi “'.$title.'” dapat diambil sebelum '.date('d/m/Y H:i',strtotime($deadline)).'.','reservasi',$id);$message='Reservasi “'.$title.'” telah dinyatakan siap.';
   }elseif($action==='cancel'){
    if(!in_array($row['status'],['menunggu','siap'],true))throw new RuntimeException('Reservasi sudah selesai dan tidak dapat dibatalkan.');
    $stmt=$conn->prepare("UPDATE perpus_reservasi SET status='dibatalkan',tanggal_selesai=NOW(),admin_id=? WHERE id=?");$stmt->bind_param('ii',$adminId,$id);$stmt->execute();$stmt->close();
    sds_perpus_notify_member($conn,$memberId,'reservasi_batal','Reservasi dibatalkan','Reservasi koleksi “'.$title.'” dibatalkan oleh petugas.','reservasi',$id);$message='Reservasi dibatalkan.';
   }elseif($action==='taken'){
    if(!in_array($row['status'],['menunggu','siap'],true))throw new RuntimeException('Reservasi ini sudah selesai.');
    $stmt=$conn->prepare("UPDATE perpus_reservasi SET status='diambil',tanggal_selesai=NOW(),admin_id=? WHERE id=?");$stmt->bind_param('ii',$adminId,$id);$stmt->execute();$stmt->close();$message='Reservasi ditandai telah diambil.';
   }else{
    if(!in_array($row['status'],['menunggu','siap'],true))throw new RuntimeException('Reservasi ini sudah selesai.');
    $stmt=$conn->prepare("UPDATE perpus_reservasi SET status='kedaluwarsa',tanggal_selesai=NOW(),admin_id=? WHERE id=?");$stmt->bind_param('ii',$adminId,$id);$stmt->execute();$stmt->close();
    sds_perpus_notify_member($conn,$memberId,'reservasi_kedaluwarsa','Reservasi kedaluwarsa','Reservasi koleksi “'.$title.'” telah kedaluwarsa.','reservasi',$id);$message='Reservasi ditandai kedaluwarsa.';
   }
   $conn->commit();sds_perpus_audit_log($conn,'update','reservasi',$id,'Perubahan status reservasi: '.$title,['status'=>$row['status']],['aksi'=>$action],$adminId);if(in_array($action,['cancel','taken','expire'],true))sds_perpus_promote_next_reservation($conn,$bookId,$adminId);
  }else throw new RuntimeException('Aksi reservasi tidak dikenali.');
 }catch(Throwable $e){try{$conn->rollback();}catch(Throwable $x){}$error=$e->getMessage();}
}
$status=trim((string)($_GET['status']??'aktif'));$q=trim((string)($_GET['q']??''));$allowedStatus=['aktif','menunggu','siap','diambil','dibatalkan','kedaluwarsa','semua'];if(!in_array($status,$allowedStatus,true))$status='aktif';
$where=[];$params=[];$types='';if($status==='aktif')$where[]="r.status IN ('menunggu','siap')";elseif($status!=='semua'){$where[]='r.status=?';$params[]=$status;$types.='s';}if($q!==''){$where[]='(b.judul LIKE ? OR a.nomor_anggota LIKE ? OR a.legacy_nama LIKE ?)';$like='%'.$q.'%';$params= array_merge($params,[$like,$like,$like]);$types.='sss';}$sql="SELECT r.*,b.judul,b.isbn,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,(SELECT COUNT(*) FROM perpus_buku_eksemplar e WHERE e.buku_id=r.buku_id AND e.status='tersedia') tersedia,(SELECT COUNT(*) FROM perpus_reservasi q2 WHERE q2.buku_id=r.buku_id AND q2.status IN ('menunggu','siap') AND (q2.tanggal_reservasi<r.tanggal_reservasi OR (q2.tanggal_reservasi=r.tanggal_reservasi AND q2.id<=r.id))) posisi FROM perpus_reservasi r JOIN perpus_buku b ON b.id=r.buku_id JOIN perpus_anggota a ON a.id=r.anggota_id".($where?' WHERE '.implode(' AND ',$where):'')." ORDER BY FIELD(r.status,'siap','menunggu','diambil','kedaluwarsa','dibatalkan'),r.tanggal_reservasi LIMIT 500";$stmt=$conn->prepare($sql);if($params)$stmt->bind_param($types,...$params);$stmt->execute();$rr=$stmt->get_result();$rows=[];while($rr&&($x=$rr->fetch_assoc())){$x['profile']=sds_perpus_identity_profile($conn,(string)$x['pemilik_tipe'],(int)($x['pemilik_id']??0),$x);$rows[]=$x;}$stmt->close();
$stats=[];foreach(['menunggu','siap','diambil','kedaluwarsa'] as $s){$stmt=$conn->prepare('SELECT COUNT(*) total FROM perpus_reservasi WHERE status=?');$stmt->bind_param('s',$s);$stmt->execute();$stats[$s]=(int)($stmt->get_result()->fetch_assoc()['total']??0);$stmt->close();}
