,strtotime($r['batas_ambil']))?></div><?php endif;?></td><td><div><?=date('d/m/Y H:i',strtotime($r['tanggal_reservasi']))?></div><div class="small text-muted"><?=perpus_h(ucfirst($r['sumber']))?></div></td><td class="text-end"><div class="btn-group btn-group-sm"><?php if($r['status']==='menunggu'):?><form method="post"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="ready"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-outline-info" <?=(int)$r['tersedia']<=0?'disabled':''?> title="Nyatakan siap"><i data-feather="check-circle"></i></button></form><?php endif;?><?php if(in_array($r['status'],['menunggu','siap'],true)):?><form method="post" onsubmit="return confirm('Tandai reservasi telah diambil?')"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="taken"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-outline-success" title="Sudah diambil"><i data-feather="shopping-bag"></i></button></form><form method="post" onsubmit="return confirm('Batalkan reservasi ini?')"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="cancel"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-outline-danger" title="Batalkan"><i data-feather="x"></i></button></form><?php endif;?></div></td></tr><?php endforeach;?></tbody></table></div></div></div>
